def seed():
    conn = sqlite3.connect(DB_PATH)
    c = conn.cursor()

    c.execute("DROP TABLE IF EXISTS questions")
    c.execute("""
        CREATE TABLE questions (
            id       INTEGER PRIMARY KEY AUTOINCREMENT,
            subject  TEXT NOT NULL,
            type     TEXT NOT NULL CHECK(type IN ('mcq','tf')),
            question TEXT NOT NULL,
            option_a TEXT,
            option_b TEXT,
            option_c TEXT,
            option_d TEXT,
            answer   TEXT NOT NULL,
            explanation TEXT
        )
    """)

    c.executemany("""
        INSERT INTO questions
            (subject, type, question, option_a, option_b, option_c, option_d, answer, explanation)
        VALUES (?,?,?,?,?,?,?,?,?)
    """, questions)

    conn.commit()
    print(f"✅ Seeded {len(questions)} questions into {DB_PATH}")

    for subj in ["Mathematics","Physics","Chemistry","Biology","History","English","EarthScience","Geography","MoralCivics"]:
        count = c.execute("SELECT COUNT(*) FROM questions WHERE subject=?", (subj,)).fetchone()[0]
        print(f"   {subj}: {count} questions")

    conn.close()

if __name__ == "__main__":
    seed()